const eventId = $input.first().json.body.eventId;
const sessionId = $input.first().json.body.sessionId;

if (!eventId || !sessionId) {
  throw new Error('Missing eventId or sessionId');
}

return [{ json: { eventId, sessionId, streak: $input.first().json.body.streak, coinsAwarded: $input.first().json.body.coinsAwarded } }];

// Deduplication check using static storage
// In production n8n, use a database node
const eventId = $input.first().json.eventId;

// Store processed events in workflow static data
const staticData = $getWorkflowStaticData('global');

if (!staticData.processedEvents) {
  staticData.processedEvents = {};
}

if (staticData.processedEvents[eventId]) {
  // Already processed - skip
  return [{ json: { duplicate: true, eventId, message: 'Already processed - skipping' } }];
}

// Mark as processed
staticData.processedEvents[eventId] = Date.now();

return [{ json: { duplicate: false, eventId, streak: $input.first().json.streak, coinsAwarded: $input.first().json.coinsAwarded } }];

const { eventId, streak, coinsAwarded } = $input.first().json;

// Mock notification - in production connect to WhatsApp/Twilio
const message = `🔥 Focus session complete! Streak: ${streak} days, +${coinsAwarded} coins earned!`;

console.log(`[NOTIFICATION SENT] eventId: ${eventId}`);
console.log(`[MESSAGE] ${message}`);

return [{ json: { sent: true, eventId, message, timestamp: new Date().toISOString() } }];
